// JWT Claims Extractor — decode the already-verified JWT payload
// The Webhook node has already verified the signature and expiry.
const authHeader = $json.headers?.authorization || $json.headers?.Authorization || '';
const token = authHeader.replace(/^Bearer\s+/i, '');

if (!token) {
  throw new Error('No JWT token found in Authorization header');
}

// Decode payload (middle part) — no crypto needed, already verified
const payloadB64 = token.split('.')[1];
const payload = JSON.parse(Buffer.from(payloadB64, 'base64url').toString('utf8'));

return [{
  json: {
    ...$json,
    jwtClaims: {
      user_id: payload.sub || payload.user_id,
      username: payload.username,
      role: payload.role
    }
  }
}];

const body = $json.body || {};
const messages = body.messages || [];
const userMsg = [...messages].reverse().find(m => m.role === 'user');

if (!userMsg || !userMsg.content || userMsg.content.trim().length === 0) {
  return [{ json: { __error: true, errorMsg: 'Leere Eingabe. Bitte gib etwas ein.', allMessages: messages } }];
}

// user_id comes from JWT claims — body.user_id is ignored
const userId = $json.jwtClaims?.user_id;
const username = $json.jwtClaims?.username;
const role = $json.jwtClaims?.role;
const sessionId = body.session_id || require('crypto').randomUUID();

return [{
  json: {
    __error: false,
    userMessage: userMsg.content.trim(),
    userId,
    username,
    role,
    sessionId,
    allMessages: messages,
    requestStartMs: Date.now()
  }
}];

const errorMsg = $json.errorMsg || 'Ungültige Eingabe.';
const now = Math.floor(Date.now() / 1000);
return [{ json: {
  id: 'chatcmpl-err-' + now.toString(36),
  object: 'chat.completion',
  created: now,
  model: 'alice',
  choices: [{ index: 0, message: { role: 'assistant', content: errorMsg }, finish_reason: 'stop' }],
  usage: { prompt_tokens: 0, completion_tokens: 0, total_tokens: 0 }
}}];

const text = $json.userMessage || '';
const SPLITTERS = ['und dann', 'und danach', 'und außerdem', 'und', 'dann', 'danach', 'außerdem', 'sowie', 'zusätzlich', 'auch noch'];
const FILLER = /^(bitte|mal|noch|auch|doch|kurz)\s+/gi;
const PUNCT = /[,\.;]+/;

function stripFillers(str) {
  let prev = '';
  let result = str;
  while (result !== prev) {
    prev = result;
    result = result.replace(FILLER, '').trim();
  }
  return result;
}

function splitText(input) {
  let parts = [input];
  for (const sep of SPLITTERS) {
    const regex = new RegExp(`\\b${sep}\\b`, 'gi');
    parts = parts.flatMap(p => p.split(regex));
  }
  parts = parts.flatMap(p => p.split(PUNCT));
  return parts
    .map(p => stripFillers(p))
    .filter(p => p.length >= 4);
}

const parts = splitText(text);
return [{ json: { ...($json), parts: parts.length > 0 ? parts : [text] } }];

const HA_URL = $env.HA_URL || 'http://homeassistant:8123';
const HA_TOKEN = $env.HA_TOKEN;
const intents = $json.intentResults.filter(r => r.matched);

const needsConfirmation = intents.filter(i => i.requiresConfirmation);
const executableIntents = intents.filter(i => !i.requiresConfirmation);

if (executableIntents.length === 0 && needsConfirmation.length > 0) {
  const names = needsConfirmation.map(i => i.entityId || i.domain).join(', ');
  return [{ json: {
    ...($json),
    __confirmationRequired: true,
    haResults: [],
    responseText: `Bist du sicher? Ich soll ${names} steuern. Bitte bestätige mit "Ja".`
  }}];
}

async function callHA(intent) {
  const parts = intent.service.split('.');
  const domain = parts[0];
  const service = parts.slice(1).join('.');
  const body = { entity_id: intent.entityId, ...(intent.parameters || {}) };
  try {
    await $helpers.httpRequest({
      method: 'POST',
      url: `${HA_URL}/api/services/${domain}/${service}`,
      headers: { 'Authorization': `Bearer ${HA_TOKEN}`, 'Content-Type': 'application/json' },
      body: JSON.stringify(body),
      timeout: 5000
    });
    return { intent, success: true };
  } catch (err) {
    const status = err.httpCode || err.status || 0;
    if (status === 401) return { intent, success: false, error: 'auth', msg: 'HA-Verbindung fehlgeschlagen, bitte Token prüfen.' };
    if (status === 404) return { intent, success: false, error: 'notfound', msg: `Ich konnte ${intent.entityId || intent.domain} nicht finden.` };
    return { intent, success: false, error: 'unknown', msg: `Fehler bei ${intent.entityId || intent.domain}.` };
  }
}

function buildText(results) {
  return results.map(r => {
    if (!r.success) return r.msg;
    const i = r.intent;
    const entity = (i.entityId || i.domain).split('.').pop().replace(/_/g, ' ');
    const svc = i.service;
    const action = svc.includes('turn_on') ? 'eingeschaltet'
      : svc.includes('turn_off') ? 'ausgeschaltet'
      : svc.includes('open') ? 'geöffnet'
      : svc.includes('close') ? 'geschlossen'
      : svc.includes('start') ? 'gestartet'
      : svc.includes('stop') ? 'gestoppt'
      : svc.includes('return') ? 'zurückgeschickt'
      : svc.includes('lock') ? 'gesperrt'
      : svc.includes('unlock') ? 'entsperrt'
      : svc.includes('arm') ? 'scharf geschaltet'
      : svc.includes('disarm') ? 'deaktiviert'
      : svc.includes('set_temperature') ? 'eingestellt'
      : 'ausgeführt';
    return `${entity.charAt(0).toUpperCase() + entity.slice(1)} ${action}.`;
  }).join(' ');
}

const haResults = await Promise.all(executableIntents.map(i => callHA(i)));

let responseText = buildText(haResults);
if (needsConfirmation.length > 0) {
  const names = needsConfirmation.map(i => i.entityId || i.domain).join(', ');
