async function callOllama(parts) {
  const userText = parts.join('. ');
  try {
    const resp = await $helpers.httpRequest({
      method: 'POST',
      url: `${OLLAMA_URL}/api/chat`,
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        model: $env.OLLAMA_MODEL || 'qwen3:14b',
        messages: [...($json.allMessages || []), { role: 'user', content: userText }],
        stream: false
      }),
      timeout: 30000
    });
    const data = typeof resp === 'string' ? JSON.parse(resp) : resp;
    return data && data.message ? data.message.content : 'Ich konnte keine Antwort generieren.';
  } catch {
    return 'Chat-Anfrage konnte nicht verarbeitet werden.';
  }
